{
  "summary": "This paper proposes Robust Informative Fine-Tuning (RIFT), an adversarial fine-tuning method for pre-trained language models that maximizes conditional mutual information between pre-trained and fine-tuned features to mitigate catastrophic forgetting and improve robustness against word substitution attacks. Experiments on sentiment analysis and natural language inference tasks demonstrate consistent improvements in robust accuracy over strong baselines.",
  "strengths": [
    {
      "point": "Addresses catastrophic forgetting in adversarial fine-tuning of PLMs",
      "evidence": "The paper identifies intensified forgetting during adversarial fine-tuning and proposes an information-theoretic approach to retain robust pre-trained features."
    },
    {
      "point": "Novel use of conditional mutual information to align features",
      "evidence": "RIFT maximizes conditional mutual information between pre-trained and fine-tuned features given class labels, encouraging retention of robust and generic linguistic features."
    },
    {
      "point": "Consistent empirical improvements on multiple datasets and models",
      "evidence": "RIFT outperforms baselines including adversarial training and regularization methods on IMDB and SNLI datasets using BERT-base and RoBERTa-base."
    },
    {
      "point": "Ablation studies validate key design choices",
      "evidence": "Experiments show conditional mutual information outperforms unconditional, and tuning the mutual information loss weight α balances robustness and accuracy."
    }
  ],
  "weaknesses": [
    {
      "point": "Lack of comparison to feature distillation or representation alignment methods",
      "evidence": "The paper does not discuss or compare against prior work on feature distillation or knowledge distillation approaches that also aim to retain pre-trained knowledge."
    },
    {
      "point": "Insufficient theoretical justification for conditioning on class labels",
      "evidence": "While conditional mutual information performs better, the paper lacks intuitive or theoretical explanation for why conditioning on labels better preserves robust features."
    },
    {
      "point": "Limited evaluation scope in tasks and robustness metrics",
      "evidence": "Experiments are restricted to two sentence-level classification tasks and evaluate robustness only via robust accuracy under word substitution attacks."
    },
    {
      "point": "Baselines omit recent strong adversarial training methods",
      "evidence": "No comparison to state-of-the-art adversarial training techniques like FreeLB or SMART, raising questions about the source of improvements."
    },
    {
      "point": "Reproducibility concerns due to missing details",
      "evidence": "Details on adversarial example generation, hyperparameter α selection, and exact feature representations used are insufficiently described."
    },
    {
      "point": "Clarity issues in algorithm presentation and terminology",
      "evidence": "Algorithm 1 lacks pseudocode for mutual information optimization; the term 'self-supervised' adversarial example generation is not clearly explained."
    },
    {
      "point": "No analysis of computational overhead or scalability",
      "evidence": "Claims of computational feasibility are not supported by quantitative training time or memory usage comparisons."
    },
    {
      "point": "Limited generalizability evaluation",
      "evidence": "No experiments on larger PLMs, multilingual models, or out-of-domain datasets to assess broader applicability."
    }
  ],
  "questions": [
    {
      "question": "How does RIFT compare to feature distillation or knowledge distillation methods in adversarial fine-tuning?",
      "motivation": "Understanding this would clarify the novelty and potential complementary benefits of RIFT."
    },
    {
      "question": "Why does conditioning mutual information on class labels better preserve robust features?",
      "motivation": "A theoretical or intuitive explanation would strengthen the methodological contribution and guide future work."
    },
    {
      "question": "Can RIFT improve robustness against other types of adversarial perturbations beyond word substitutions?",
      "motivation": "Evaluating broader robustness is important for practical deployment and understanding method limitations."
    },
    {
      "question": "What is the computational cost of RIFT compared to standard adversarial fine-tuning?",
      "motivation": "Quantifying overhead is critical for assessing feasibility in large-scale or resource-constrained settings."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
